CREATE DATABASE IF NOT EXISTS online_voting CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE online_voting;

CREATE TABLE users (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, full_name VARCHAR(120) NOT NULL, usn VARCHAR(40) NOT NULL UNIQUE, email VARCHAR(190) NOT NULL UNIQUE, phone VARCHAR(30), password VARCHAR(255) NOT NULL, role ENUM('admin','voter') NOT NULL DEFAULT 'voter', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE elections (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, title VARCHAR(180) NOT NULL, description TEXT, start_date DATETIME NOT NULL, end_date DATETIME NOT NULL, status ENUM('draft','active','completed') NOT NULL DEFAULT 'draft', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CHECK(end_date > start_date));
CREATE TABLE candidates (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, branch VARCHAR(100) NOT NULL, year VARCHAR(20) NOT NULL, manifesto TEXT, image VARCHAR(255), election_id BIGINT UNSIGNED NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT fk_candidate_election FOREIGN KEY(election_id) REFERENCES elections(id) ON DELETE CASCADE);
CREATE TABLE votes (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, voter_id BIGINT UNSIGNED NOT NULL, candidate_id BIGINT UNSIGNED NOT NULL, election_id BIGINT UNSIGNED NOT NULL, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uq_one_vote_per_election UNIQUE(voter_id,election_id), CONSTRAINT fk_vote_voter FOREIGN KEY(voter_id) REFERENCES users(id) ON DELETE RESTRICT, CONSTRAINT fk_vote_candidate FOREIGN KEY(candidate_id) REFERENCES candidates(id) ON DELETE RESTRICT, CONSTRAINT fk_vote_election FOREIGN KEY(election_id) REFERENCES elections(id) ON DELETE CASCADE, INDEX idx_vote_election(election_id));
